import { useState, useEffect } from "react"
import "./index.css"

// Define the type for a todo item
type TodoItem = {
  id: number | null
  text: string
  completed: boolean
}

const TodoList: React.FC = () => {
  const [todos, setTodos] = useState<TodoItem[]>([])
  const [inputValue, setInputValue] = useState("")

  // Fetch todos on initial mount
  useEffect(() => {
  fetchTodos().catch(err => console.error("Failed to fetch todos", err))
}, [])

const fetchTodos = async () => {
  try {
  const res = await fetch("/api/items")
  if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`)
  const data: TodoItem[] = await res.json()
setTodos(data)
} catch (error) {
  console.error("Failed to load todos", error)
}

const addTodo = async () => {
  const text = inputValue.trim()
if (!text) return

try {
const newTodo: TodoItem = await fetch("/api/items", {
  method: "POST",
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify({ text })
}) as Promise<{ id: number; text: string }>
setTodos(prev => [...prev, { id: newTodo.id, text: newTodo.text, completed: false }])
setInputValue("")
} catch (error) {
  console.error("Failed to add todo", error)
}

const toggleCompletion = async (id: number) => {
try {
const res = await fetch(`/api/items/${id}`, { method: "PUT" })
if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`)
const updatedItem: TodoItem = await res.json()
setTodos(prev => prev.map(todo => todo.id === id ? { ...todo, completed: !todo.completed } : todo))
} catch (error) {
  console.error("Failed to toggle completion", error)
}

const deleteTodo = async (id: number) => {
try {
await fetch(`/api/items/${id}`, { method: "DELETE" })
setTodos(prev => prev.filter(todo => todo.id !== id))
} catch (error) {
  console.error("Failed to delete todo", error)
}

return (
  <div className="container max-w-lg mx-auto py-12">
  <h1 className="text-4xl font-extrabold text-center mb-8 text-transparent bg-clip-text bg-clip-text-gradient from-indigo-500 to-pink-500">
  Todo List
</h1>

{todos.length === 0 ? (
  <div className="text-center py-16 border-2 border-dashed border-gray-200 rounded-xl bg-white/5 backdrop-blur-sm">
  <p className="text-lg text-gray-500 mb-4">You don't have any todos yet!</p>
<button 
  onClick={() => setInputValue("Example todo item")}>
  Add Sample Todo
</button>
</div>
) : (
  <div className="space-y-3 max-h-[60vh] overflow-y-auto p-4 bg-white/5 backdrop-blur-sm rounded-xl shadow-lg">
{todos.map((todo) => (
  <div 
    key={todo.id} 
    className={`flex items-center justify-between p-4 transition-all duration-200 border-l-4 ${todo.completed ? 'border-green-500' : 'border-transparent'} bg-white/5 hover:bg-white/10 rounded-lg cursor-pointer ${todo.completed ? 'opacity-70 line-through text-gray-400' : ''}`}
    onClick={() => setTodos(prev => prev.map(todo => todo.id === todo.id ? { ...todo, completed: !todo.completed } : todo)))}
>
<input 
  type="checkbox" 
  checked={todo.completed} 
  onChange={() => toggleCompletion(todo.id)}
/>
<span className={`flex-grow ${todo.completed ? 'text-gray-400 italic' : ''}`}>
  {todo.text}
</span>
{!todo.completed && (
<button 
  onClick={(e) => e.stopPropagation()}
  className="ml-4 text-sm font-medium py-1 px-3 rounded-full transition duration-150 bg-red-500 hover:bg-red-600 active:scale-[0.98] disabled:cursor-not-allowed"
disabled={!todo.text}
type="button"
>
  Delete
</button>
)}
</div>
))}

{todos.length > 0 && (
<div className="mt-6 flex items-center justify-between p-4 bg-white/5 backdrop-blur-sm rounded-xl shadow-inner">
<h2 className="text-2xl font-bold text-gray-700 mr-4">
  {todos.filter(t => !t.completed).length}
</h2>
<button 
  onClick={() => setTodos(prev => prev.map(todo => ({ ...todo, completed: false })))}
className="flex items-center gap-2 py-2 px-4 rounded-full transition duration-150 bg-green-500 hover:bg-green-600 active:scale-[0.98] focus:ring-2 focus:ring-green-300"
type="button"
disabled={todos.length === 0}
>
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v3"/><path d="M22 12h-3"/><path d="M2 22l10-10L22 2"/></svg>
  <span className={`capitalize ${todos.length === 0 ? 'text-gray-400' : ''}`}>
  {todos.filter(t => !t.completed).length}
</span>
<button 
  onClick={() => setTodos(prev => prev.map(todo => ({ ...todo, completed: false })))}
className="focus:ring-2 focus:ring-green-300 disabled:cursor-not-allowed"
type="button"
disabled={todos.length === 0}
>
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v3"/><path d="M22 12h-3"/><path d="M2 22l10-10L22 2"/></svg>
<span className="text-sm font-semibold">
  {todos.filter(t => !t.completed).length}
</span>
</button>
)}

<div className="mt-8 flex items-center gap-4 max-w-[600px] w-full">
<input 
  type="text" 
  placeholder="What needs to be done?" 
value={inputValue}
onChange={(e) => setInputValue(e.target.value)}
className={`flex-grow p-4 border-2 ${inputValue.length > 0 ? 'border-indigo-500' : 'border-gray-200'} rounded-xl focus:ring-2 focus:ring-indigo-500 transition duration-200 placeholder:text-gray-300 outline-none`}
placeholder="Enter a new todo item..."
/>
<button 
  onClick={addTodo}
type="button"
disabled={inputValue.trim().length === 0}
className={`relative px-8 py-4 rounded-xl transition duration-200 ${inputValue.trim().length > 0 ? 'bg-gradient-to-r from-indigo-500 to-pink-500 hover:from-indigo-600 hover:to-pink-600 active:scale-[0.98] focus:ring-2 focus:ring-indigo-300' : 'bg-gray-100 hover:bg-gray-200 disabled:cursor-not-allowed'}`}
type="submit"
disabled={inputValue.trim().length === 0}
>
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v3"/><path d="M22 12h-3"/><path d="M2 22l10-10L22 2"/></svg>
<span className={`text-lg ${inputValue.trim().length > 0 ? 'text-white' : 'text-gray-400'}`}>
  {inputValue.trim().length > 0 ? 'Add' : ''}
</span>
</button>
)}

<div className="pt-12 pb-16">
  <p className="text-center text-sm text-gray-500 mt-8">
  Total items: {todos.length} | {todos.filter(t => t.completed).length} Completed
</p>
</div>

</div>
)
}

